using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos: sync I/O (ToList, SaveChanges, etc.) now throws — use async.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" in OnModelCreating.
        // If the discriminator name had not been preserved, this query would return zero results
        // because EF Core 9 defaults to "$type" for new documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

